import os
import shutil
import tarfile
from zipfile import ZipFile

def backup_directory(directory_path, output_format):
    if not os.path.exists(directory_path):
        print("Directory does not exist.")
        return

    base_name = os.path.basename(directory_path)
    archive_name = f"{base_name}.{output_format}"

    if output_format == "tar.gz":
        with tarfile.open(archive_name, "w:gz") as tar:
            tar.add(directory_path, arcname=base_name)
    elif output_format == "tar.bz2":
        with tarfile.open(archive_name, "w:bz2") as tar:
            tar.add(directory_path, arcname=base_name)
    elif output_format == "zip":
        with ZipFile(archive_name, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for root, dirs, files in os.walk(directory_path):
                for file in files:
                    file_path = os.path.join(root, file)
                    arcname = os.path.relpath(file_path, start=directory_path)
                    zipf.write(file_path, arcname)
    elif output_format == "7z":
        try:
            import py7zr
            with py7zr.SevenZipFile(archive_name, 'w') as z:
                z.writeall(directory_path, base_name)
        except ImportError:
            print("py7zr library is not installed. Please install it to use 7z format.")
    else:
        print("Unsupported compression format.")

